import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { chaptersAPI, progressAPI } from '../services/api';
import VirtualKeyboard from '../components/VirtualKeyboard';

const Lesson = () => {
  const { chapterId, lessonId } = useParams();
  const navigate = useNavigate();

  const [lessonData, setLessonData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Typing state
  const [userInput, setUserInput] = useState('');
  const [currentIndex, setCurrentIndex] = useState(0);
  const [errors, setErrors] = useState(0);
  const [startTime, setStartTime] = useState(null);
  const [timeElapsed, setTimeElapsed] = useState(0);
  const [isComplete, setIsComplete] = useState(false);
  const [showResults, setShowResults] = useState(false);

  // Single-line display state
  const [currentLineIndex, setCurrentLineIndex] = useState(0);
  const [lines, setLines] = useState([]);
  const [lineTransition, setLineTransition] = useState(false);

  const inputRef = useRef(null);
  const timerRef = useRef(null);

  useEffect(() => {
    fetchLesson();
    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, [chapterId, lessonId]);

  useEffect(() => {
    if (lessonData && lessonData.lesson) {
      // Split content into lines for single-line display
      const content = lessonData.lesson.content;
      const lessonType = lessonData.lesson.lessonType;

      if (lessonType === 'paragraph') {
        // Paragraphs show full text
        setLines([content]);
      } else if (lessonType === 'sentences') {
        // Split by sentences
        const sentenceLines = content.split(/\.\s+/).filter(s => s.trim());
        setLines(sentenceLines.map(s => s + '.'));
      } else {
        // For intro and words: split into manageable lines (15-20 words per line)
        const words = content.split(/\s+/);
        const linesArray = [];
        const wordsPerLine = 15;

        for (let i = 0; i < words.length; i += wordsPerLine) {
          const lineWords = words.slice(i, i + wordsPerLine);
          linesArray.push(lineWords.join(' '));
        }

        setLines(linesArray);
      }
    }
  }, [lessonData]);

  useEffect(() => {
    if (inputRef.current && !isComplete) {
      inputRef.current.focus();
    }
  }, [isComplete, currentLineIndex]);

  const fetchLesson = async () => {
    try {
      const response = await chaptersAPI.getLesson(chapterId, lessonId);
      setLessonData(response.data);
    } catch (err) {
      console.error('Error fetching lesson:', err);
      setError('Failed to load lesson');
    } finally {
      setLoading(false);
    }
  };

  const startTimer = () => {
    if (!startTime) {
      const now = Date.now();
      setStartTime(now);
      timerRef.current = setInterval(() => {
        setTimeElapsed((Date.now() - now) / 1000);
      }, 100);
    }
  };

  const calculateStats = () => {
    const content = lessonData.lesson.content;
    const timeInMinutes = timeElapsed / 60 || 0.1;
    const wordsTyped = userInput.trim().split(/\s+/).length;
    const wpm = Math.round(wordsTyped / timeInMinutes);
    const accuracy = Math.max(0, Math.round(((content.length - errors) / content.length) * 100));

    return { wpm, accuracy, timeElapsed: Math.round(timeElapsed) };
  };

  const handleSubmit = async () => {
    if (timerRef.current) {
      clearInterval(timerRef.current);
    }

    const actualTimeElapsed = startTime ? (Date.now() - startTime) / 1000 : 0;
    setTimeElapsed(actualTimeElapsed);

    const stats = calculateStats();

    try {
      await progressAPI.submitLesson({
        chapterId,
        lessonId,
        wpm: stats.wpm,
        accuracy: stats.accuracy
      });

      setIsComplete(true);
      setShowResults(true);
    } catch (err) {
      console.error('Error submitting progress:', err);
      alert('Failed to save progress. Please try again.');
    }
  };

  const moveToNextLine = () => {
    if (currentLineIndex < lines.length - 1) {
      setLineTransition(true);
      setTimeout(() => {
        setCurrentLineIndex(currentLineIndex + 1);
        setUserInput('');
        setCurrentIndex(0);
        setLineTransition(false);
      }, 300);
    } else {
      // All lines completed
      handleSubmit();
    }
  };

  const handleInputChange = (e) => {
    const value = e.target.value;
    const lessonType = lessonData.lesson.lessonType;

    if (!startTime) {
      startTimer();
    }

    // For paragraph type, use full content
    if (lessonType === 'paragraph') {
      const content = lessonData.lesson.content;
      const currentChar = content[currentIndex];
      const typedChar = value[value.length - 1];

      if (typedChar !== currentChar && value.length > userInput.length) {
        setErrors(errors + 1);
      }

      setUserInput(value);
      setCurrentIndex(value.length);

      if (value.length >= content.length) {
        handleSubmit();
      }
      return;
    }

    // For single-line types: work with current line only
    const currentLine = lines[currentLineIndex] || '';

    // Character by character validation
    if (lessonType === 'intro' || lessonType === 'random-words' || lessonType === 'meaningful-words') {
      const currentChar = currentLine[currentIndex];
      const typedChar = value[value.length - 1];

      if (value.length > userInput.length) {
        if (typedChar !== currentChar) {
          setErrors(errors + 1);
          return; // Don't advance on wrong key
        }

        setUserInput(value);
        setCurrentIndex(currentIndex + 1);

        // Check if line is complete
        if (currentIndex + 1 >= currentLine.length) {
          moveToNextLine();
        }
      } else {
        setUserInput(value);
        setCurrentIndex(value.length);
      }
    } else if (lessonType === 'sentences') {
      // For sentences, allow typing and check on Enter
      setUserInput(value);
    }
  };

  const handleKeyDown = (e) => {
    const lessonType = lessonData?.lesson?.lessonType;

    if (lessonType === 'sentences' && e.key === 'Enter') {
      e.preventDefault();

      const currentLine = lines[currentLineIndex] || '';
      const trimmedInput = userInput.trim();
      const trimmedLine = currentLine.trim();

      // Count errors
      const errorCount = Math.abs(trimmedInput.length - trimmedLine.length);
      for (let i = 0; i < Math.min(trimmedInput.length, trimmedLine.length); i++) {
        if (trimmedInput[i] !== trimmedLine[i]) {
          setErrors(errors + 1);
        }
      }
      setErrors(errors + errorCount);

      // Move to next line
      moveToNextLine();
    }
  };

  const renderSingleLine = () => {
    const lessonType = lessonData.lesson.lessonType;
    const currentLine = lines[currentLineIndex] || '';

    if (lessonType === 'paragraph') {
      // Paragraph shows full content with character highlighting
      const content = lessonData.lesson.content;
      return content.split('').map((char, index) => {
        let className = '';

        if (index < userInput.length) {
          className = userInput[index] === char ? 'correct' : 'incorrect';
        } else if (index === userInput.length) {
          className = 'current';
        }

        return (
          <span key={index} className={className}>
            {char}
          </span>
        );
      });
    }

    // Single-line display for intro, words, sentences
    return (
      <div className={`single-line-container ${lineTransition ? 'slide-up' : ''}`}>
        {currentLine.split('').map((char, index) => {
          let className = '';

          if (index < currentIndex) {
            className = userInput[index] === char ? 'correct' : 'incorrect';
          } else if (index === currentIndex) {
            className = 'current';
          }

          return (
            <span key={index} className={`char ${className}`}>
              {char}
            </span>
          );
        })}
      </div>
    );
  };

  const getCurrentKey = () => {
    if (!lessonData || isComplete) return null;

    const lessonType = lessonData.lesson.lessonType;

    if (lessonType === 'paragraph') {
      const content = lessonData.lesson.content;
      return content[currentIndex];
    }

    const currentLine = lines[currentLineIndex] || '';
    return currentLine[currentIndex];
  };

  if (loading) {
    return <div className="loading">Loading lesson...</div>;
  }

  if (error || !lessonData) {
    return (
      <div className="container">
        <div className="error">{error || 'Lesson not found'}</div>
        <button className="btn btn-primary" onClick={() => navigate('/learn')}>
          Back to Lessons
        </button>
      </div>
    );
  }

  const { chapter, lesson } = lessonData;
  const showKeyboard = lesson.lessonType !== 'paragraph';
  const stats = showResults ? calculateStats() : null;

  return (
    <div className="container">
      <div className="typing-interface">
        <div className="typing-header">
          <div>
            <h3>Chapter {chapter.chapterNumber}: {chapter.chapterTitle}</h3>
            <p style={{ color: '#666' }}>
              Lesson {lesson.lessonNumber}: {lesson.lessonTitle}
            </p>
          </div>
          <div className="typing-stats">
            <div className="stat-item">
              <span>Time</span>
              <strong>{Math.round(timeElapsed)}s</strong>
            </div>
            <div className="stat-item">
              <span>Accuracy</span>
              <strong>
                {currentIndex > 0
                  ? Math.round(((currentIndex - errors) / currentIndex) * 100)
                  : 100}
                %
              </strong>
            </div>
            <div className="stat-item">
              <span>Errors</span>
              <strong>{errors}</strong>
            </div>
          </div>
        </div>

        <div className="typing-content-single-line">
          {!isComplete && lines.length > 0 && (
            <div className="line-indicator">
              Line {currentLineIndex + 1} of {lines.length}
            </div>
          )}
          {renderSingleLine()}
        </div>

        {!isComplete && (
          <>
            <textarea
              ref={inputRef}
              className="typing-input"
              value={userInput}
              onChange={handleInputChange}
              onKeyDown={handleKeyDown}
              placeholder={
                lesson.lessonType === 'sentences'
                  ? 'Type the sentence and press Enter...'
                  : 'Start typing...'
              }
              autoFocus
            />
            <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center' }}>
              <button className="btn btn-success" onClick={handleSubmit}>
                Submit Lesson
              </button>
              <button className="btn btn-secondary" onClick={() => navigate('/learn')}>
                Exit
              </button>
            </div>
          </>
        )}

        {showKeyboard && !isComplete && (
          <VirtualKeyboard activeKey={getCurrentKey()} />
        )}

        {showResults && stats && (
          <div className="results-modal">
            <div className="results-content">
              <h2>Lesson Complete! 🎉</h2>
              <div className="results-stats">
                <div className="result-stat">
                  <h3>{stats.wpm}</h3>
                  <p>Words Per Minute</p>
                </div>
                <div className="result-stat">
                  <h3>{stats.accuracy}%</h3>
                  <p>Accuracy</p>
                </div>
                <div className="result-stat">
                  <h3>{stats.timeElapsed}s</h3>
                  <p>Time Taken</p>
                </div>
                <div className="result-stat">
                  <h3>{errors}</h3>
                  <p>Errors</p>
                </div>
              </div>
              <div className="results-actions">
                <button className="btn btn-primary" onClick={() => navigate('/learn')}>
                  Back to Lessons
                </button>
                <button
                  className="btn btn-secondary"
                  onClick={() => window.location.reload()}
                >
                  Try Again
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Lesson;
